import{_ as s,o as a,c as t,a0 as n}from"./chunks/framework.DTwdCQre.js";const u=JSON.parse('{"title":"Tutorial 2: Your First Tool Call","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tutorials/02-first-tool-call.md","filePath":"guide/tutorials/02-first-tool-call.md","lastUpdated":1775554522000}'),l={name:"guide/tutorials/02-first-tool-call.md"};function i(o,e,r,p,d,c){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="tutorial-2-your-first-tool-call" tabindex="-1">Tutorial 2: Your First Tool Call <a class="header-anchor" href="#tutorial-2-your-first-tool-call" aria-label="Permalink to &quot;Tutorial 2: Your First Tool Call&quot;">​</a></h1><p>Learn how claude-code-Go uses tools to interact with your system.</p><h2 id="what-are-tools" tabindex="-1">What are Tools? <a class="header-anchor" href="#what-are-tools" aria-label="Permalink to &quot;What are Tools?&quot;">​</a></h2><p>Tools are functions the AI can call to:</p><ul><li>Read and write files</li><li>Execute shell commands</li><li>Search code</li><li>Browse the web</li><li>And more...</li></ul><p>Think of tools as the AI&#39;s hands — they let it actually <em>do</em> things rather than just talk about them.</p><h2 id="built-in-tools" tabindex="-1">Built-in Tools <a class="header-anchor" href="#built-in-tools" aria-label="Permalink to &quot;Built-in Tools&quot;">​</a></h2><p>claude-code-Go includes 10 built-in tools:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th><th>Example</th></tr></thead><tbody><tr><td><code>Read</code></td><td>Read file contents</td><td><code>Read main.go</code></td></tr><tr><td><code>Write</code></td><td>Create new files</td><td><code>Write config.json {&quot;key&quot;: &quot;value&quot;}</code></td></tr><tr><td><code>Edit</code></td><td>Modify existing files</td><td><code>Edit main.go:10 change &quot;foo&quot; to &quot;bar&quot;</code></td></tr><tr><td><code>Glob</code></td><td>Find files by pattern</td><td><code>Glob *.go</code></td></tr><tr><td><code>Grep</code></td><td>Search file contents</td><td><code>Grep &quot;func main&quot;</code></td></tr><tr><td><code>Bash</code></td><td>Execute shell commands</td><td><code>Bash ls -la</code></td></tr><tr><td><code>Diff</code></td><td>Show file differences</td><td><code>Diff file.go</code></td></tr><tr><td><code>Tree</code></td><td>Show directory structure</td><td><code>Tree src/</code></td></tr><tr><td><code>WebFetch</code></td><td>Fetch web content</td><td><code>WebFetch https://example.com</code></td></tr><tr><td><code>TodoWrite</code></td><td>Manage todo lists</td><td><code>TodoWrite &quot;Fix bug&quot;</code></td></tr></tbody></table><h2 id="how-tool-calls-work" tabindex="-1">How Tool Calls Work <a class="header-anchor" href="#how-tool-calls-work" aria-label="Permalink to &quot;How Tool Calls Work&quot;">​</a></h2><p>When you ask the AI to do something, it follows this process:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. You: &quot;Read the README&quot;</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>2. AI thinks: &quot;I need to use the Read tool&quot;</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>3. AI calls tool: Read {&quot;file_path&quot;: &quot;README.md&quot;}</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>4. Tool executes and returns content</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>5. AI receives result and summarizes it</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>6. You see the summary</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="hands-on-example" tabindex="-1">Hands-On Example <a class="header-anchor" href="#hands-on-example" aria-label="Permalink to &quot;Hands-On Example&quot;">​</a></h2><h3 id="step-1-create-a-test-file" tabindex="-1">Step 1: Create a test file <a class="header-anchor" href="#step-1-create-a-test-file" aria-label="Permalink to &quot;Step 1: Create a test file&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Hello, World!&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="step-2-ask-the-ai-to-read-it" tabindex="-1">Step 2: Ask the AI to read it <a class="header-anchor" href="#step-2-ask-the-ai-to-read-it" aria-label="Permalink to &quot;Step 2: Ask the AI to read it&quot;">​</a></h3><p>In the claude-code-Go REPL:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Read the file test.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You&#39;ll see output like:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🛠️  Using tool: Read</span></span>
<span class="line"><span>   file_path: test.txt</span></span>
<span class="line"><span></span></span>
<span class="line"><span>📄 Content:</span></span>
<span class="line"><span>Hello, World!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💬 The file contains a simple greeting message.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="step-3-edit-the-file" tabindex="-1">Step 3: Edit the file <a class="header-anchor" href="#step-3-edit-the-file" aria-label="Permalink to &quot;Step 3: Edit the file&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Edit test.txt to say &quot;Hello, claude-code-Go!&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The AI will:</p><ol><li>Read the current content</li><li>Determine what needs to change</li><li>Use the Edit tool</li><li>Confirm the change</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🛠️  Using tool: Edit</span></span>
<span class="line"><span>   file_path: test.txt</span></span>
<span class="line"><span>   old_string: Hello, World!</span></span>
<span class="line"><span>   new_string: Hello, claude-code-Go!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✅ File updated successfully.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="step-4-verify-the-change" tabindex="-1">Step 4: Verify the change <a class="header-anchor" href="#step-4-verify-the-change" aria-label="Permalink to &quot;Step 4: Verify the change&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Read test.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="permission-system" tabindex="-1">Permission System <a class="header-anchor" href="#permission-system" aria-label="Permalink to &quot;Permission System&quot;">​</a></h2><p>By default, claude-code-Go runs in &quot;WorkspaceWrite&quot; mode:</p><ul><li>✅ Can read any file</li><li>✅ Can write to files in your workspace</li><li>⚠️ Will prompt before dangerous operations</li><li>❌ Cannot access sensitive files (<code>.env</code>, <code>.ssh</code>, etc.)</li></ul><h3 id="granting-permission" tabindex="-1">Granting Permission <a class="header-anchor" href="#granting-permission" aria-label="Permalink to &quot;Granting Permission&quot;">​</a></h3><p>If the AI needs permission:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Delete the test.txt file</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️  Permission required</span></span>
<span class="line"><span>The tool Bash with command &quot;rm test.txt&quot; requires DangerFullAccess mode.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Options:</span></span>
<span class="line"><span>1. Type &quot;/allow&quot; to grant one-time permission</span></span>
<span class="line"><span>2. Type &quot;/mode DangerFullAccess&quot; to switch modes</span></span>
<span class="line"><span>3. Cancel and try a safer approach</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="exercise-file-operations" tabindex="-1">Exercise: File Operations <a class="header-anchor" href="#exercise-file-operations" aria-label="Permalink to &quot;Exercise: File Operations&quot;">​</a></h2><p>Try these exercises:</p><ol><li><strong>Create a file</strong>: Ask the AI to create a new file</li><li><strong>Edit it</strong>: Make changes to the file</li><li><strong>Search</strong>: Use Grep to find content</li><li><strong>Directory listing</strong>: Use Tree to see folder structure</li></ol><h2 id="understanding-tool-selection" tabindex="-1">Understanding Tool Selection <a class="header-anchor" href="#understanding-tool-selection" aria-label="Permalink to &quot;Understanding Tool Selection&quot;">​</a></h2><p>The AI decides which tool to use based on your request:</p><table tabindex="0"><thead><tr><th>Your Request</th><th>AI Chooses</th></tr></thead><tbody><tr><td>&quot;Show me main.go&quot;</td><td>Read tool</td></tr><tr><td>&quot;Find all Go files&quot;</td><td>Glob tool</td></tr><tr><td>&quot;Search for TODO comments&quot;</td><td>Grep tool</td></tr><tr><td>&quot;What files are in this directory?&quot;</td><td>Tree or Bash tool</td></tr><tr><td>&quot;Run the tests&quot;</td><td>Bash tool</td></tr></tbody></table><p>The AI is smart about tool selection, but you can be explicit:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Use the Glob tool to find all test files</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./03-agent-loop.html">Tutorial 3: Understanding the Agent Loop</a> - Learn how the AI makes decisions</li><li><a href="./04-permission-system.html">Tutorial 4: Permission System</a> - Deep dive into security</li><li><a href="./../../api/tools.html">API Reference</a> - Complete tool documentation</li></ul>`,43)])])}const b=s(l,[["render",i]]);export{u as __pageData,b as default};
